export default function Page() {
  const [lang, setLang] = useState<keyof typeof TEXT>("en");
  const [dark, setDark] = useState(false);
  const t = TEXT[lang] || TEXT.en;

  // form state
  const [name, setName] = useState("");
  const [phone, setPhone] = useState("");
  const [email, setEmail] = useState("");
  const [business, setBusiness] = useState("");
  const [websiteType, setWebsiteType] = useState("");
  const [details, setDetails] = useState("");
  const [brandNotes, setBrandNotes] = useState("");
  const [files, setFiles] = useState<FileList | null>(null);

  const [sending, setSending] = useState(false);
  const [sent, setSent] = useState(false);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    if (typeof window === "undefined") return;
    const saved = localStorage.getItem("lang") as keyof typeof TEXT | null;
    const navLang = navigator?.language?.slice(0, 2) as keyof typeof TEXT;
    if (saved && TEXT[saved]) setLang(saved);
    else if (navLang && Object.keys(TEXT).includes(navLang)) setLang(navLang);
    const prefersDark = window.matchMedia("(prefers-color-scheme: dark)").matches;
    setDark(localStorage.getItem("dark") === "true" || (!localStorage.getItem("dark") && prefersDark));
  }, []);

  useEffect(() => {
    document.documentElement.lang = lang;
    document.documentElement.classList.toggle("dark", dark);
    localStorage.setItem("lang", lang);
    localStorage.setItem("dark", String(dark));
  }, [lang, dark]);

  // Helper: try to upload files to /api/upload if present (non-blocking)
  const tryUploadFiles = async (files: FileList | null) => {
    if (!files || files.length === 0) return null;
    try {
      const form = new FormData();
      Array.from(files).forEach((f) => form.append("files", f));
      // Placeholder endpoint — create /api/upload server-side if you want actual storage
      await fetch("/api/upload", { method: "POST", body: form });
      return true;
    } catch (e) {
      // ignore upload failures for now (we fallback to WhatsApp + asking for further files)
      return null;
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);

    // Basic client-side validation
    if (!name.trim()) {
      setError("Please enter your name.");
      return;
    }
    if (!email.trim()) {
      setError("Please enter your email.");
      return;
    }

    setSending(true);

    // Attempt background upload (non-blocking)
    tryUploadFiles(files);

    // Build message for WhatsApp (encode newlines)
    const fileList = files ? Array.from(files).map((f) => f.name).join(", ") : "None";
    const messageLines = [
      "Hi NMAS! 👋",
      "",
      "I'd like the €50/month website.",
      "",
      `Name: ${name}`,
      `Phone: ${phone || "–"}`,
      `Email: ${email}`,
      `Business: ${business || "–"}`,
      `Website type: ${websiteType || "–"}`,
      "",
      `Details: ${details || "–"}`,
      `Brand notes: ${brandNotes || "–"}`,
      `Files: ${fileList}`,
    ];
    const text = encodeURIComponent(messageLines.join("\n"));

    // open WhatsApp (international number) in a new tab
    const waUrl = `https://wa.me/27674877278?text=${text}`;
    window.open(waUrl, "_blank");

    setSent(true);
    setSending(false);

    // temporary UI acknowledgment
    setTimeout(() => setSent(false), 6000);
  };

  return (
    <>
      <link rel="icon" href="/favicon.ico" />
      <meta name="description" content="Professional websites for €50/month. No upfront payment. Live in 7 days." />

      <div className="min-h-screen bg-gradient-to-b from-zinc-50 via-white to-zinc-50 dark:from-zinc-950 dark:via-black dark:to-zinc-950 text-zinc-900 dark:text-zinc-100 pb-24">

        {/* Header */}
        <header className="fixed top-0 inset-x-0 z-50 bg-white/80 dark:bg-black/80 backdrop-blur-xl border-b border-zinc-200/50 dark:border-zinc-800/50">
          <div className="max-w-7xl mx-auto px-6 py-4 flex items-center justify-between">
            <div className="flex items-center gap-4">
              <div className="font-bold">NMAS INNOVATIONS</div>
              <div className="text-sm text-zinc-500 dark:text-zinc-400">€50/month · Live in 7 days</div>
            </div>

            <div className="flex items-center gap-3">
              <button
                aria-label="Toggle theme"
                onClick={() => setDark((d) => !d)}
                className="p-2 rounded-xl border border-transparent hover:border-zinc-200 dark:hover:border-zinc-700"
              >
                {dark ? <Sun className="h-5 w-5" /> : <Moon className="h-5 w-5" />}
              </button>

              <select
                value={lang}
                onChange={(e) => setLang(e.target.value as keyof typeof TEXT)}
                className="text-sm p-2 rounded-xl border"
                aria-label="Select language"
              >
                {Object.keys(FLAGS).map((k) => (
                  <option key={k} value={k}>{TEXT[k as keyof typeof TEXT]?.lang || k}</option>
                ))}
              </select>
            </div>
          </div>
        </header>

        {/* Hero */}
        <main className="pt-28 max-w-7xl mx-auto px-6">
          <section className="grid md:grid-cols-2 gap-8 items-center">
            <div>
              <h1 className="text-3xl md:text-4xl font-extrabold leading-tight">{t.heroTitle}</h1>
              <p className="mt-3 text-zinc-600 dark:text-zinc-300">{t.heroSubtitle}</p>
              <div className="mt-4 flex items-center gap-3">
                <span className="px-3 py-2 bg-green-50 text-green-700 rounded-full text-sm">{t.trustBadge}</span>
                <a href="#start" className="ml-3 inline-flex items-center gap-2 px-4 py-2 rounded-2xl bg-black text-white">
                  <MessageCircle className="h-4 w-4" /> {t.formTitle}
                </a>
              </div>
            </div>

            <div>
              <div className="rounded-2xl p-6 bg-white dark:bg-zinc-900 shadow">
                <h3 className="font-semibold mb-2">{t.sectionEverything}</h3>
                <ul className="space-y-2 text-sm text-zinc-600 dark:text-zinc-300">
                  {t.bullets.map((b, i) => (
                    <li key={i} className="flex items-start gap-3">
                      <div className="flex-shrink-0 w-8 h-8 rounded-lg bg-zinc-100 dark:bg-zinc-800 flex items-center justify-center text-xs font-medium">
                        {b.icon[0]}
                      </div>
                      <div>
                        <div className="font-medium text-zinc-900 dark:text-zinc-100">{b.title}</div>
                        <div className="text-xs">{b.desc}</div>
                      </div>
                    </li>
                  ))}
                </ul>
              </div>
            </div>
          </section>

          {/* How it works + Form */}
          <section className="mt-12 grid md:grid-cols-3 gap-8">
            <div className="md:col-span-1 space-y-4">
              <h2 className="text-xl font-bold">{t.howItWorks}</h2>

              <div className="space-y-4 text-sm text-zinc-700 dark:text-zinc-300">
                <div>
                  <h4 className="font-semibold">{t.step1}</h4>
                  <p className="text-sm">{t.step1desc}</p>
                </div>
                <div>
                  <h4 className="font-semibold">{t.step2}</h4>
                  <p className="text-sm">{t.step2desc}</p>
                </div>
                <div>
                  <h4 className="font-semibold">{t.step3}</h4>
                  <p className="text-sm">{t.step3desc}</p>
                </div>
              </div>
            </div>

            <div className="md:col-span-2">
              {/* Project brief form */}
              <div id="start" className="rounded-2xl p-6 bg-white dark:bg-zinc-900 shadow">
                <h3 className="text-lg font-bold mb-1">{t.step1}</h3>
                <p className="text-sm text-zinc-600 dark:text-zinc-400 mb-4">{t.step1desc}</p>

                <form onSubmit={handleSubmit} className="grid gap-3">
                  <div className="grid md:grid-cols-2 gap-3">
                    <label className="flex flex-col text-sm">
                      <span className="font-medium">Your name *</span>
                      <input
                        required
                        value={name}
                        onChange={(e) => setName(e.target.value)}
                        className="mt-1 p-2 rounded-xl border bg-transparent"
                        placeholder="Jane Doe"
                      />
                    </label>

                    <label className="flex flex-col text-sm">
                      <span className="font-medium">Business / Project name</span>
                      <input
                        value={business}
                        onChange={(e) => setBusiness(e.target.value)}
                        className="mt-1 p-2 rounded-xl border bg-transparent"
                        placeholder="Acme Coffee"
                      />
                    </label>
                  </div>

                  <div className="grid md:grid-cols-2 gap-3">
                    <label className="flex flex-col text-sm">
                      <span className="font-medium">Email *</span>
                      <input
                        required
                        type="email"
                        value={email}
                        onChange={(e) => setEmail(e.target.value)}
                        className="mt-1 p-2 rounded-xl border bg-transparent"
                        placeholder="you@company.com"
                      />
                    </label>

                    <label className="flex flex-col text-sm">
                      <span className="font-medium">Phone</span>
                      <input
                        value={phone}
                        onChange={(e) => setPhone(e.target.value)}
                        className="mt-1 p-2 rounded-xl border bg-transparent"
                        placeholder="+44 7..."
                      />
                    </label>
                  </div>

                  <label className="flex flex-col text-sm">
                    <span className="font-medium">Type of website</span>
                    <select
                      value={websiteType}
                      onChange={(e) => setWebsiteType(e.target.value)}
                      className="mt-1 p-2 rounded-xl border bg-transparent"
                    >
                      <option value="">Select...</option>
                      <option>Business Website</option>
                      <option>E-commerce</option>
                      <option>Portfolio</option>
                      <option>Landing Page</option>
                      <option>Booking / Appointments</option>
                      <option>Other</option>
                    </select>
                  </label>

                  <label className="flex flex-col text-sm">
                    <span className="font-medium">Details (what should be on the site?)</span>
                    <textarea
                      value={details}
                      onChange={(e) => setDetails(e.target.value)}
                      rows={4}
                      className="mt-1 p-2 rounded-xl border bg-transparent"
                      placeholder="Describe pages, sections, functionality, content you already have..."
                    />
                  </label>

                  <label className="flex flex-col text-sm">
                    <span className="font-medium">Brand notes (colours, tone, examples)</span>
                    <textarea
                      value={brandNotes}
                      onChange={(e) => setBrandNotes(e.target.value)}
                      rows={3}
                      className="mt-1 p-2 rounded-xl border bg-transparent"
                      placeholder="e.g., 'minimal, warm, right-aligned logo' or 'use blue #123456'"
                    />
                  </label>

                  <label className="flex flex-col text-sm">
                    <span className="font-medium">Upload photos / files (optional)</span>
                    <input
                      type="file"
                      multiple
                      onChange={(e) => setFiles(e.target.files)}
                      className="mt-2"
                    />
                    {files && files.length > 0 && (
                      <div className="mt-2 text-xs text-zinc-500 dark:text-zinc-400">
                        Selected: {Array.from(files).map((f) => f.name).join(", ")}
                      </div>
                    )}
                  </label>

                  {error && <div className="text-sm text-red-500">{error}</div>}

                  <div className="mt-3 grid md:grid-cols-2 gap-3">
                    <button
                      type="submit"
                      className="w-full inline-flex items-center justify-center gap-2 px-4 py-3 rounded-2xl bg-black text-white font-semibold hover:opacity-95"
                      aria-disabled={sending}
                    >
                      {sending ? "Sending..." : <><Send className="h-4 w-4" /> Send via WhatsApp</>}
                    </button>

                    <button
                      type="button"
                      onClick={() => {
                        // quick call-to-action: open WhatsApp chat without prefilled message
                        window.open("https://wa.me/27674877278", "_blank");
                      }}
                      className="w-full inline-flex items-center justify-center gap-2 px-4 py-3 rounded-2xl border"
                    >
                      <MessageCircle className="h-4 w-4" /> Chat on WhatsApp
                    </button>
                  </div>

                  {sent && <div className="text-sm text-green-600 mt-2">Message opened in WhatsApp — we’ll reply shortly.</div>}
                </form>
              </div>
            </div>
          </section>

          {/* FAQ */}
          <section className="mt-12">
            <div className="rounded-2xl p-6 bg-white dark:bg-zinc-900 shadow">
              <h3 className="text-lg font-bold mb-4">{t.faqTitle}</h3>
              <div className="grid md:grid-cols-2 gap-4">
                {t.faq.map((f, i) => (
                  <div key={i}>
                    <div className="font-semibold">{f.q}</div>
                    <div className="text-sm text-zinc-600 dark:text-zinc-400">{f.a}</div>
                  </div>
                ))}
              </div>
            </div>
          </section>

          {/* Footer */}
          <footer className="mt-12 text-center text-sm text-zinc-500 dark:text-zinc-400">
            {t.footer}
          </footer>
        </main>
      </div>
    </>
  );
}
